SELECT A.NMODIFY_APPLY_SEQ , A.PIP_PREFIX , A.SFIRST_ADDR , A.SLAST_ADDR , A.SWHOISREQUESTID , A.NWHOIS_SEQ , A.BEF_SORGNAME , A.AFT_SORGNAME , A.SSTAT_CD , A.SSTAT_NM , A.DAPPLY_DT , A.SAPPLY_ID , A.SAPPLY_ID_NM , A.DAPPROVAL_DT , A.RNUM FROM ( SELECT A.NMODIFY_APPLY_SEQ , A.PIP_PREFIX , A.SFIRST_ADDR , A.SLAST_ADDR , A.SWHOISREQUESTID , A.NWHOIS_SEQ , A.BEF_SORGNAME , A.AFT_SORGNAME , A.SSTAT_CD , A.SSTAT_NM , A.DAPPLY_DT , A.SAPPLY_ID , A.SAPPLY_ID_NM , A.DAPPROVAL_DT , ROWNUM RNUM FROM ( SELECT A.NMODIFY_APPLY_SEQ , A.PIP_PREFIX , A.SFIRST_ADDR , A.SLAST_ADDR , A.SWHOISREQUESTID , A.NWHOIS_SEQ , A.BEF_SORGNAME , A.AFT_SORGNAME , A.SSTAT_CD , A.SSTAT_NM , A.DAPPLY_DT , A.SAPPLY_ID , B.SUSER_NM AS SAPPLY_ID_NM , A.DAPPROVAL_DT FROM BIF.TB_WHOIS_MODIFY A LEFT OUTER JOIN MST.TB_USER_BAS B ON B.SUSER_ID = A.SAPPLY_ID WHERE 1 = 1
AND A.SFIRST_ADDR = #{sfirstAddr, jdbcType=VARCHAR}
AND A.SLAST_ADDR = #{slastAddr, jdbcType=VARCHAR}
AND A.SWHOISREQUESTID = #{swhoisrequestid, jdbcType=VARCHAR}
AND A.NWHOIS_SEQ = #{nwhoisseq, jdbcType=BIGINT}
AND A.SSTAT_CD = #{searchCnd, jdbcType=VARCHAR}
AND A.SAPPLY_ID = #{sApplyId, jdbcType=VARCHAR}
AND A.DAPPLY_DT = #{dApplyDt, jdbcType=TIMESTAMP}
AND (A.PIP_PREFIX >>= (SELECT BIF.UF_SEARCH_IP_TO_ADDRESS(#{searchWrd, jdbcType=VARCHAR}) AS SIP FROM DUAL) OR A.PIP_PREFIX <<= (SELECT BIF.UF_SEARCH_IP_TO_ADDRESS(#{searchWrd, jdbcType=VARCHAR}) AS SIP FROM DUAL) )
ORDER BY A.DAPPLY_DT
ASC
DESC
ASC
ORDER BY A.NMODIFY_APPLY_SEQ
ASC
DESC
ASC
ORDER BY A.DAPPROVAL_DT
ASC
DESC
ASC
) A WHERE ROWNUM <= #{lastIndex} ) A WHERE RNUM >= #{firstIndex}

SELECT A.NMODIFY_APPLY_SEQ , (CASE WHEN B.NWHOIS_SEQ IS NULL OR (STRPOS(B.SWHOISRESULT_MSG, '[2306]') > 0 AND B.SWHOISRESULT_CD = '03' AND B.SREQUEST_CD = '03')THEN 'N' ELSE 'Y' END) AS TRANS_YN , C.SSAID , A.SFIRST_ADDR , A.SLAST_ADDR , A.SWHOISREQUESTID , A.NWHOIS_SEQ , A.BEF_SORGNAME , A.BEF_SADDR , A.BEF_SEORGNAME , A.BEF_SEADDR , A.BEF_SZIPCODE , A.AFT_SORGNAME , A.AFT_SADDR , NVL(A.AFT_SADDR_DETAIL, ' ') AS AFT_SADDR_DETAIL , A.AFT_SEORGNAME , A.AFT_SEADDR , NVL(A.AFT_SEADDR_DETAIL, ' ') AS AFT_SEADDR_DETAIL , TRIM(A.AFT_SZIPCODE) AS AFT_SZIPCODE , A.SSTAT_CD , A.SSTAT_NM , A.DAPPLY_DT , A.SAPPLY_ID , A.DAPPROVAL_DT , A.SAPPROVAL_ID , A.DCREATE_DT , A.SCREATE_ID , A.DMODIFY_DT , A.SMODIFY_ID , A.SREJECT_RSN FROM BIF.TB_WHOIS_MODIFY A LEFT OUTER JOIN BIF.TB_WHOIS B ON B.NWHOIS_SEQ = A.NWHOIS_SEQ LEFT OUTER JOIN BIF.TB_WHOIS_USER C ON C.SSAID = B.SSAID WHERE 1 = 1
AND A.NMODIFY_APPLY_SEQ = #{nmodify_apply_seq, jdbcType=BIGINT}
AND A.SFIRST_ADDR = #{sfirstAddr, jdbcType=VARCHAR}
AND A.SLAST_ADDR = #{slastAddr, jdbcType=VARCHAR}
AND A.NWHOIS_SEQ = #{nwhoisseq, jdbcType=BIGINT}

SELECT
	count(1) totalCount
FROM BIF.TB_WHOIS_MODIFY A
WHERE 
	1 = 1

		AND A.SFIRST_ADDR = #{sfirstAddr, jdbcType=VARCHAR}


		AND A.SLAST_ADDR = #{slastAddr, jdbcType=VARCHAR}  


		AND A.SWHOISREQUESTID = #{swhoisrequestid, jdbcType=VARCHAR}  


		AND A.NWHOIS_SEQ = #{nwhoisseq, jdbcType=BIGINT}  


		AND A.SSTAT_CD = #{searchCnd, jdbcType=VARCHAR}  


		AND A.SAPPLY_ID = #{sApplyId, jdbcType=VARCHAR}


		AND A.DAPPLY_DT = #{dApplyDt, jdbcType=TIMESTAMP}  


		AND (A.PIP_PREFIX >>= (SELECT BIF.UF_SEARCH_IP_TO_ADDRESS(#{searchWrd, jdbcType=VARCHAR}) AS SIP FROM DUAL)
  		OR A.PIP_PREFIX <<= (SELECT BIF.UF_SEARCH_IP_TO_ADDRESS(#{searchWrd, jdbcType=VARCHAR}) AS SIP FROM DUAL) )

