mapper.update:
UPDATE BIF.TB_WHOIS_MODIFY A SET
	 A.DMODIFY_DT = CURRENT_TIMESTAMP
	 ,	A.SMODIFY_ID = #{smodifyId, jdbcType=VARCHAR}

		, A.AFT_SORGNAME = #{sAftOrgName, jdbcType=VARCHAR}


		, A.AFT_SADDR = #{sAftOrgAddr, jdbcType=VARCHAR}


		, A.AFT_SADDR_DETAIL = #{sAftOrgAddrDetail, jdbcType=VARCHAR}


		, A.AFT_SZIPCODE = #{sAftZipCode, jdbcType=VARCHAR}


		, A.AFT_SEORGNAME = #{sAftEOrgName, jdbcType=VARCHAR}


		, A.AFT_SEADDR = #{sAftEOrgAddr, jdbcType=VARCHAR}


		, A.AFT_SEADDR_DETAIL = #{sAftEOrgAddrDetail, jdbcType=VARCHAR}

WHERE
	A.NMODIFY_APPLY_SEQ = #{nmodify_apply_seq, jdbcType=BIGINT}

mapper.delete:
DELETE FROM BIF.TB_WHOIS_MODIFY A
WHERE
	A.NMODIFY_APPLY_SEQ = #{nmodify_apply_seq, jdbcType=BIGINT}

