UPDATE BIF.TB_WHOIS_MODIFY A SET
	 A.DAPPROVAL_DT = CURRENT_TIMESTAMP
	 ,	A.SAPPROVAL_ID = #{sApprovalId, jdbcType=VARCHAR}
	 ,  A.SSTAT_CD = #{sStatCd, jdbcType=VARCHAR} 
	 ,  A.SSTAT_NM = #{sStatNm, jdbcType=VARCHAR} 

		, A.SREJECT_RSN = #{sreject_rsn, jdbcType=VARCHAR}

WHERE
